import { describe, it, expect, beforeAll, afterAll, vi } from 'vitest';
import { coreApi } from './api';
import { useLayerStore } from './stores/layerStore';
import { useVolumeStore } from './stores/volumeStore';
import { useCrosshairStore } from './stores/crosshairSlice';
import type { LayerSpec, VolumeHandleInfo } from '@brainflow/api';

// Mock the Tauri API
vi.mock('@tauri-apps/api/core', () => ({
	invoke: vi.fn()
}));

const mockVolumeInfo: VolumeHandleInfo = {
	handle: 'test-handle-123',
	dims: [64, 64, 32],
	voxel_size: [2.0, 2.0, 3.0],
	data_range: [0, 255],
	dtype: 'uint8'
};

const mockGpuInfo = {
	texture_id: 'texture-123',
	layer_id: 'layer-123',
	format: 'r8unorm',
	size: [64, 64, 32]
};

describe('NIfTI Loading Integration Test', () => {
	let handle: string | null = null;

	beforeAll(() => {
		// Reset stores
		useLayerStore.setState({ layers: [], activeLayerId: null });
		useVolumeStore.setState({ volumes: new Map() });
		useCrosshairStore.setState({ worldCoord: [0, 0, 0], voxelCoords: new Map() });
	});

	afterAll(async () => {
		// Clean up
		if (handle) {
			try {
				await coreApi.release_layer_gpu_resources(handle);
			} catch (err) {
				// Ignore cleanup errors in tests
			}
		}
	});

	it('should load a NIfTI file following the correct sequence', async () => {
		const { invoke } = await import('@tauri-apps/api/core');
		const mockInvoke = invoke as any;

		// Mock the API responses
		mockInvoke.mockImplementation((cmd: string, args: any) => {
			switch (cmd) {
				case 'plugin:api-bridge|init_render_loop':
					return Promise.resolve();
				case 'plugin:api-bridge|load_file':
					return Promise.resolve(mockVolumeInfo);
				case 'plugin:api-bridge|request_layer_gpu_resources':
					return Promise.resolve(mockGpuInfo);
				case 'plugin:api-bridge|release_layer_gpu_resources':
					return Promise.resolve();
				default:
					return Promise.reject(new Error(`Unknown command: ${cmd}`));
			}
		});

		// Step 1: Initialize render loop
		await coreApi.init_render_loop();
		expect(mockInvoke).toHaveBeenCalledWith('plugin:api-bridge|init_render_loop', {});

		// Step 2: Load the file
		const volumeInfo = await coreApi.load_file('/test/path.nii.gz');
		expect(volumeInfo).toEqual(mockVolumeInfo);
		handle = volumeInfo.handle;

		// Step 3: Store volume info
		useVolumeStore.getState().addVolume({
			id: handle,
			handle,
			metadata: {
				dims: volumeInfo.dims,
				voxel_size: volumeInfo.voxel_size,
				data_range: volumeInfo.data_range,
				dtype: volumeInfo.dtype
			}
		});
		expect(useVolumeStore.getState().getVolume(handle)?.handle).toEqual(handle);

		// Step 4: Request GPU resources
		const gpuInfo = await coreApi.request_layer_gpu_resources(handle);
		expect(gpuInfo).toEqual(mockGpuInfo);

		// Step 5: Create layer spec
		const layerSpec: LayerSpec = {
			name: 'Test Volume',
			volume_id: handle,
			colormap: 'grayscale',
			opacity: 1.0,
			visible: true,
			min: volumeInfo.data_range[0],
			max: volumeInfo.data_range[1],
			window: null,
			level: null
		};

		// Step 6: Add to layer store
		layerStore.addLayer({
			id: handle,
			handle: handle,
			spec: layerSpec,
			volumeInfo
		});

		const layers = layerStore.getLayers();
		expect(layers).toHaveLength(1);
		expect(layers[0].spec).toEqual(layerSpec);

		// Step 7: Initialize crosshair
		const center = volumeInfo.dims.map(d => Math.floor(d / 2));
		crosshairSliceStore.setCrosshairVoxel(center as [number, number, number]);

		const state = crosshairSliceStore.getState();
		expect(state.crosshairVoxel).toEqual([32, 32, 16]);

		// Verify final state
		expect(volumeStore.getAllVolumes()).toHaveLength(1);
		expect(layerStore.getLayers()).toHaveLength(1);
		expect(crosshairSliceStore.getState().crosshairVoxel).toEqual([32, 32, 16]);
	});

	it('should handle errors gracefully', async () => {
		const { invoke } = await import('@tauri-apps/api/core');
		const mockInvoke = invoke as any;

		// Mock a failure
		mockInvoke.mockRejectedValueOnce(new Error('Failed to load file'));

		// Should throw error
		await expect(coreApi.load_file('/bad/path.nii')).rejects.toThrow('Failed to load file');

		// Stores should remain unchanged
		expect(volumeStore.getAllVolumes()).toHaveLength(1); // From previous test
		expect(layerStore.getLayers()).toHaveLength(1); // From previous test
	});

	it('should clean up GPU resources on failure', async () => {
		const { invoke } = await import('@tauri-apps/api/core');
		const mockInvoke = invoke as any;

		// Mock successful load but failed GPU allocation
		mockInvoke.mockImplementation((cmd: string, args: any) => {
			switch (cmd) {
				case 'plugin:api-bridge|load_file':
					return Promise.resolve({
						...mockVolumeInfo,
						handle: 'test-handle-456'
					});
				case 'plugin:api-bridge|request_layer_gpu_resources':
					return Promise.reject(new Error('GPU allocation failed'));
				case 'plugin:api-bridge|release_layer_gpu_resources':
					return Promise.resolve();
				default:
					return Promise.reject(new Error(`Unknown command: ${cmd}`));
			}
		});

		const testHandle = 'test-handle-456';
		let gpuAllocated = false;

		try {
			// Load file (should succeed)
			const volumeInfo = await coreApi.load_file('/test/path2.nii.gz');
			expect(volumeInfo.handle).toBe(testHandle);

			// Request GPU resources (should fail)
			await coreApi.request_layer_gpu_resources(testHandle);
			gpuAllocated = true; // This shouldn't execute
		} catch (err) {
			expect(err).toEqual(new Error('GPU allocation failed'));
			expect(gpuAllocated).toBe(false);

			// Verify cleanup was attempted
			await coreApi.release_layer_gpu_resources(testHandle);
			expect(mockInvoke).toHaveBeenCalledWith(
				'plugin:api-bridge|release_layer_gpu_resources',
				{ volume_id: testHandle }
			);
		}
	});
});

