  const cachedVolume: VolumeHandle = {
    volumeId: 'cached-123',
    dimensions: [256, 256, 128],
    voxelSize: [1, 1, 1],
    metadata: { sourcePath: '/path/to/volume.nii' }
  } as any;

  // Add to offline cache
  (service as any).offlineCache.set('/path/to/volume.nii', cachedVolume);

  // Make load fail with a non-retryable error after mockWithRetry gives up
  const error = new Error('Network error');
  error.name = 'NetworkError';
  mockLoad.mockClear().mockRejectedValue(error);

  // Configure mockWithRetry to fail after retries and trigger fallback
  mockWithRetry.mockImplementationOnce(async (fn, options) => {
    // Try the function and let it fail
    try {
      return await fn();
    } catch (e) {
      // Fallback to cache
      const cached = (service as any).offlineCache.get('/path/to/volume.nii');
      if (cached) {
        notificationService.warning?.('Using offline cached version', { duration: 5000 });
        return cached.volumeId;
      }
      throw e;
    }
  });

  const result = await service.load('/path/to/volume.nii');

  expect(result).toBe('cached-123');
  expect(notificationService.warning).toHaveBeenCalledWith(
    'Using offline cached version',
    { duration: 5000 }
  );
});

