      window.dispatchEvent(new Event('online'));

      expect(notificationService.success).toHaveBeenCalledWith(
        'Connection restored',
        { duration: 3000 }
      );
      expect(mockResetCircuitBreaker).toHaveBeenCalled();
    });
  });

