      for (let i = 0; i < 3; i++) {
        try {
          await service.getSliceData('test-volume', 'axial', 64);
        } catch (e) {
          // Expected
        }
        await vi.advanceTimersByTimeAsync(1000);
      }

      const status = service.getHealthStatus();
      expect(status.sliceFailures).toBeGreaterThan(0);
    });
  });

