      mockLoad.mockClear().mockResolvedValue('volume-123');

      const volumeHandle: VolumeHandle = {
        volumeId: 'volume-123',
        dimensions: [256, 256, 128],
        metadata: { sourcePath: '/path/to/volume.nii' }
      } as any;

