import '@testing-library/jest-dom';
import { vi } from 'vitest';
import { cleanup } from '@testing-library/svelte';
import { nanoid } from 'nanoid';

// Mock Tauri API globally
vi.mock('@tauri-apps/api/core', () => ({
  invoke: vi.fn().mockResolvedValue(undefined)
}));

// Mock nanoid with predictable IDs for tests
vi.mock('nanoid', () => ({
  nanoid: vi.fn(() => `test-id-${Math.random().toString(36).substr(2, 9)}`)
}));

// Mock WebGPU globally to prevent real GPU context creation
if (!global.navigator) {
  global.navigator = {} as any;
}

global.navigator.gpu = {
  requestAdapter: vi.fn().mockResolvedValue(null),
  getPreferredCanvasFormat: vi.fn().mockReturnValue('bgra8unorm')
} as any;

// Track created blob URLs for cleanup
const createdBlobUrls = new Set<string>();

// Mock URL.createObjectURL to track blob URLs
const originalCreateObjectURL = URL.createObjectURL;
URL.createObjectURL = function(blob: Blob): string {
  const url = originalCreateObjectURL.call(this, blob);
  createdBlobUrls.add(url);
  return url;
};

// Reset singleton instances
function resetSingletons() {
  // Reset EventBus if it exists
  if ((globalThis as any).__eventBus) {
    (globalThis as any).__eventBus.removeAllListeners();
    delete (globalThis as any).__eventBus;
  }

  // Reset DI Container if it exists
  if ((globalThis as any).__container) {
    (globalThis as any).__container = null;
  }

  // Reset any cached stores
  if ((globalThis as any).__stores) {
    (globalThis as any).__stores = new Map();
  }
}

// Setup before each test
beforeEach(() => {
  vi.useFakeTimers();
  vi.clearAllMocks();
  resetSingletons();
});

// Comprehensive cleanup after each test
afterEach(() => {
  // Clean up DOM
  cleanup();

  // Clear all timers
  vi.clearAllTimers();
  vi.runOnlyPendingTimers();
  vi.useRealTimers();

  // Clear all mocks
  vi.clearAllMocks();

  // Reset singletons
  resetSingletons();

  // Clean up blob URLs
  createdBlobUrls.forEach(url => {
    try {
      URL.revokeObjectURL(url);
    } catch (e) {
      // Ignore errors during cleanup
    }
  });
  createdBlobUrls.clear();

  // Clear any pending promises
  vi.runAllTimers();
});

