/**
 * OrthogonalViewContainer Component Tests
 * Tests for the container component that manages orthogonal volume views
 */
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
// import userEvent from '@testing-library/user-event';
import OrthogonalViewContainer from './OrthogonalViewContainer.svelte';
import { getService } from '../../di/Container';
import { getEventBus } from '../../events/EventBus';
import { useLayerStore } from '../../stores/layerStore';
import { useCrosshairStore } from '../../stores/crosshairSlice';
// Define ViewType enum inline for tests
enum ViewType {
  Axial = 'axial',
  Coronal = 'coronal',
  Sagittal = 'sagittal'
}
import type { LayerService } from '../../services/LayerService';
import type { CrosshairService } from '../../services/CrosshairService';
import type { NotificationService } from '../../services/NotificationService';
import type { EventBus } from '../../events/EventBus';
import '@testing-library/jest-dom';

// Mock OrthogonalViewGPU component
// Mock OrthogonalViewGPU component
vi.mock('../OrthogonalViewGPU.svelte', () => ({
  default: vi.fn()
}));

// Mock dependencies
vi.mock('../../di/Container');
vi.mock('../../events/EventBus');
vi.mock('../../stores/layerStore');
vi.mock('../../stores/crosshairSlice');
vi.mock('../../stores/zustandBridge', () => ({
  zustandToReadable: vi.fn((store) => ({
    subscribe: vi.fn((fn) => {
      // Call with initial state
      fn(store.getState());
      return () => {};
    })
  }))
}));
const mockOrthogonalViewGPU = vi.mocked(vi.fn());

describe('OrthogonalViewContainer', () => {
  let mockLayerService: Partial<LayerService>;
  let mockCrosshairService: Partial<CrosshairService>;
  let mockNotificationService: Partial<NotificationService>;
  let mockEventBus: Partial<EventBus>;
  let mockEventUnsubscribes: (() => void)[];
  let mockLayerStoreUnsubscribe: () => void;
  let mockCrosshairStoreUnsubscribe: () => void;

  const mockLayers = [
    {
      id: 'layer1',
      spec: {
        Volume: {
          id: 'layer1',
          source_resource_id: 'volume1',
          colormap: 'grayscale',
          slice_axis: null,
          slice_index: null
        },
        name: 'Brain T1',
        visible: true,
        opacity: 1.0,
        min: 0,
        max: 255
      },
      volumeInfo: {
        data_range: [0, 255],
        dimensions: [256, 256, 150],
        voxel_size: [1, 1, 1]
      },
      gpu: true // Has GPU resources
    },
    {
      id: 'layer2',
      spec: {
        Volume: {
          id: 'layer2',
          source_resource_id: 'volume2',
          colormap: 'hot',
          slice_axis: null,
          slice_index: null
        },
        name: 'Brain Mask',
        visible: false,
        opacity: 0.7,
        min: -100,
        max: 2000
      },
      volumeInfo: {
        data_range: [-100, 2000],
        dimensions: [256, 256, 150],
        voxel_size: [1, 1, 1]
      },
      gpu: true // Has GPU resources
    }
  ];

  const mockCrosshairState = {
    worldCoord: [128, 128, 75],
    voxelCoords: new Map(),
    visible: true,
    color: '#FF0000',
    thickness: 2,
    isAnimating: false,
    setWorldCoord: vi.fn(),
    setVoxelCoord: vi.fn(),
    removeVoxelCoord: vi.fn(),
    setVisible: vi.fn(),
    setAppearance: vi.fn(),
    setAnimating: vi.fn(),
    getVoxelCoord: vi.fn(),
    getSliceIndices: vi.fn()
  };

  beforeEach(() => {
    // Setup mock services
    mockLayerService = {
      setActiveLayer: vi.fn(),
      updateLayer: vi.fn().mockResolvedValue(undefined),
      requestGpuResources: vi.fn().mockResolvedValue({})
    };

    mockCrosshairService = {
      setWorldCoordinate: vi.fn().mockResolvedValue(undefined),
      getWorldCoordinate: vi.fn().mockReturnValue([128, 128, 75]),
      setVisible: vi.fn().mockResolvedValue(undefined)
    };

    mockNotificationService = {
      error: vi.fn(),
      warning: vi.fn(),
      info: vi.fn()
    };

    mockEventUnsubscribes = [];
    mockEventBus = {
      emit: vi.fn(),
      on: vi.fn().mockImplementation((event: string, handler: Function) => {
        const unsubscribe = vi.fn();
        mockEventUnsubscribes.push(unsubscribe);
        return unsubscribe;
      })
    };

    mockLayerStoreUnsubscribe = vi.fn();
    mockCrosshairStoreUnsubscribe = vi.fn();

    // Mock getService
    vi.mocked(getService).mockImplementation(async (serviceName: string) => {
      switch (serviceName) {
        case 'layerService':
          return mockLayerService as LayerService;
        case 'crosshairService':
          return mockCrosshairService as CrosshairService;
        case 'notificationService':
          return mockNotificationService as NotificationService;
        default:
          throw new Error(`Unknown service: ${serviceName}`);
      }
    });

    // Mock getEventBus
    vi.mocked(getEventBus).mockReturnValue(mockEventBus as EventBus);

    // Mock stores
    vi.mocked(useLayerStore).getState = vi.fn().mockReturnValue({
      layers: mockLayers,
      activeLayerId: 'layer1'
    });
    vi.mocked(useLayerStore).subscribe = vi.fn().mockReturnValue(mockLayerStoreUnsubscribe);

    vi.mocked(useCrosshairStore).getState = vi.fn().mockReturnValue(mockCrosshairState);
    vi.mocked(useCrosshairStore).subscribe = vi.fn().mockReturnValue(mockCrosshairStoreUnsubscribe);

    // Reset component mock
    mockOrthogonalViewGPU.mockClear();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe('Component Rendering', () => {
    it('should render with default props', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(screen.getByText('Synchronize view scales')).toBeInTheDocument();
      });
    });

    it('should render three OrthogonalViewGPU components', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalledTimes(3);

        // Check each view type is rendered
        const calls = mockOrthogonalViewGPU.mock.calls;
        expect(calls.some(call => call[0].viewType === ViewType.Axial)).toBe(true);
        expect(calls.some(call => call[0].viewType === ViewType.Coronal)).toBe(true);
        expect(calls.some(call => call[0].viewType === ViewType.Sagittal)).toBe(true);
      });
    });

    it('should pass selected layer ID to views', async () => {
      render(OrthogonalViewContainer, {
        props: { selectedLayerId: 'layer1' }
      });

      await waitFor(() => {
        mockOrthogonalViewGPU.mock.calls.forEach(call => {
          expect(call[0].layerId).toBe('layer1');
        });
      });
    });

    it('should show loading state initially', () => {
      // Mock no GPU layers initially
      vi.mocked(useLayerStore).getState.mockReturnValue({
        layers: [{ ...mockLayers[0], gpu: false }],
        activeLayerId: 'layer1'
      });

      render(OrthogonalViewContainer);

      expect(screen.getByText('Initializing GPU context...')).toBeInTheDocument();
    });

    it('should show error state on GPU initialization failure', async () => {
      vi.mocked(getService).mockRejectedValueOnce(new Error('Service unavailable'));

      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(screen.getByText(/Failed to initialize:/)).toBeInTheDocument();
      });
    });
  });

  describe('Service Initialization', () => {
    it('should initialize all services on mount', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(getService).toHaveBeenCalledWith('layerService');
        expect(getService).toHaveBeenCalledWith('crosshairService');
        expect(getService).toHaveBeenCalledWith('notificationService');
      });
    });

    it('should handle service initialization errors', async () => {
      vi.mocked(getService).mockRejectedValueOnce(new Error('Service not found'));

      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(screen.getByText(/Failed to initialize:/)).toBeInTheDocument();
      });
    });
  });

  describe('GPU Context Management', () => {
    it('should wait for GPU resources when no layers have GPU', async () => {
      vi.mocked(useLayerStore).getState.mockReturnValue({
        layers: [{ ...mockLayers[0], gpu: false }],
        activeLayerId: 'layer1'
      });

      render(OrthogonalViewContainer);

      expect(screen.getByText('Initializing GPU context...')).toBeInTheDocument();

      // Simulate GPU ready event
      const gpuReadyHandler = vi.mocked(mockEventBus.on).mock.calls.find(
        call => call[0] === 'layer.gpu.ready'
      )?.[1];

      await gpuReadyHandler?.();

      await waitFor(() => {
        expect(screen.queryByText('Initializing GPU context...')).not.toBeInTheDocument();
      });
    });

    it('should handle GPU context loss', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalled();
      });

      // Simulate GPU context loss
      const contextLostHandler = vi.mocked(mockEventBus.on).mock.calls.find(
        call => call[0] === 'gpu.context.lost'
      )?.[1];

      contextLostHandler?.();

      await waitFor(() => {
        expect(screen.getByText('GPU context lost. Please refresh the page.')).toBeInTheDocument();
      });
    });

    it('should handle GPU context restoration', async () => {
      render(OrthogonalViewContainer);

      // First lose context
      const contextLostHandler = vi.mocked(mockEventBus.on).mock.calls.find(
        call => call[0] === 'gpu.context.lost'
      )?.[1];
      contextLostHandler?.();

      await waitFor(() => {
        expect(screen.getByText('GPU context lost. Please refresh the page.')).toBeInTheDocument();
      });

      // Then restore it
      const contextRestoredHandler = vi.mocked(mockEventBus.on).mock.calls.find(
        call => call[0] === 'gpu.context.restored'
      )?.[1];
      contextRestoredHandler?.();

      await waitFor(() => {
        expect(screen.queryByText('GPU context lost. Please refresh the page.')).not.toBeInTheDocument();
      });
    });
  });

  describe('Viewport Management', () => {
    it('should handle viewport changes from views', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalled();
      });

      // Get the onViewportChange handler
      const axialView = mockOrthogonalViewGPU.mock.calls.find(
        call => call[0].viewType === ViewType.Axial
      );
      const onViewportChange = axialView[0].onViewportChange;

      const newViewport = { scale: 2.0, offset: [10, 20] as [number, number] };
      onViewportChange(ViewType.Axial, newViewport);

      expect(mockEventBus.emit).toHaveBeenCalledWith('viewcontainer.viewport.changed', {
        viewType: ViewType.Axial,
        viewport: newViewport,
        allViewports: expect.any(Object)
      });
    });

    it('should synchronize view scales when enabled', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalled();
      });

      // Scale sync should be enabled by default
      const checkbox = screen.getByRole('checkbox');
      expect(checkbox).toBeChecked();

      // Change scale in one view
      const axialView = mockOrthogonalViewGPU.mock.calls.find(
        call => call[0].viewType === ViewType.Axial
      );
      const onViewportChange = axialView[0].onViewportChange;

      onViewportChange(ViewType.Axial, { scale: 3.0, offset: [0, 0] });

      // Should emit scale sync event
      expect(mockEventBus.emit).toHaveBeenCalledWith('viewcontainer.scales.synchronized', {
        scale: 3.0
      });
    });

    it('should not synchronize scales when disabled', async () => {
      render(OrthogonalViewContainer);

      const checkbox = await screen.findByRole('checkbox');

      // Uncheck the sync checkbox
      fireEvent.click(checkbox);

      expect(mockEventBus.emit).toHaveBeenCalledWith('viewcontainer.sync.changed', {
        enabled: false
      });

      // Reset mock
      vi.mocked(mockEventBus.emit).mockClear();

      // Change scale in one view
      const axialView = mockOrthogonalViewGPU.mock.calls.find(
        call => call[0].viewType === ViewType.Axial
      );
      const onViewportChange = axialView[0].onViewportChange;

      onViewportChange(ViewType.Axial, { scale: 3.0, offset: [0, 0] });

      // Should NOT emit scale sync event
      expect(mockEventBus.emit).not.toHaveBeenCalledWith('viewcontainer.scales.synchronized', expect.any(Object));
    });

    it('should respond to external sync requests', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalled();
      });

      // Get sync viewport handler
      const syncHandler = vi.mocked(mockEventBus.on).mock.calls.find(
        call => call[0] === 'viewcontainer.sync.viewports'
      )?.[1];

      syncHandler?.({ scale: 4.0 });

      expect(mockEventBus.emit).toHaveBeenCalledWith('viewcontainer.scales.synchronized', {
        scale: 4.0
      });
    });
  });

  describe('Crosshair Interaction', () => {
    it('should handle crosshair clicks from views', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalled();
      });

      // Get the onCrosshairClick handler
      const axialView = mockOrthogonalViewGPU.mock.calls.find(
        call => call[0].viewType === ViewType.Axial
      );
      const onCrosshairClick = axialView[0].onCrosshairClick;

      const worldCoord: [number, number, number] = [100, 120, 80];
      await onCrosshairClick(ViewType.Axial, worldCoord);

      expect(mockCrosshairService.setWorldCoordinate).toHaveBeenCalledWith(worldCoord);
      expect(mockEventBus.emit).toHaveBeenCalledWith('viewcontainer.crosshair.clicked', {
        viewType: ViewType.Axial,
        worldCoord
      });
    });

    it('should handle crosshair update errors', async () => {
      vi.mocked(mockCrosshairService.setWorldCoordinate).mockRejectedValueOnce(
        new Error('Invalid coordinates')
      );

      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockOrthogonalViewGPU).toHaveBeenCalled();
      });

      const axialView = mockOrthogonalViewGPU.mock.calls.find(
        call => call[0].viewType === ViewType.Axial
      );
      const onCrosshairClick = axialView[0].onCrosshairClick;

      await onCrosshairClick(ViewType.Axial, [100, 120, 80]);

      expect(mockNotificationService.error).toHaveBeenCalledWith('Failed to update crosshair position');
    });
  });

  describe('Event Handling', () => {
    it('should subscribe to all required events', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockEventBus.on).toHaveBeenCalledWith('viewcontainer.sync.viewports', expect.any(Function));
        expect(mockEventBus.on).toHaveBeenCalledWith('viewcontainer.sync.toggle', expect.any(Function));
        expect(mockEventBus.on).toHaveBeenCalledWith('gpu.context.lost', expect.any(Function));
        expect(mockEventBus.on).toHaveBeenCalledWith('gpu.context.restored', expect.any(Function));
        expect(mockEventBus.on).toHaveBeenCalledWith('layer.gpu.ready', expect.any(Function));
      });
    });

    it('should handle sync toggle events', async () => {
      render(OrthogonalViewContainer);

      const checkbox = await screen.findByRole('checkbox');
      expect(checkbox).toBeChecked();

      // Get sync toggle handler
      const toggleHandler = vi.mocked(mockEventBus.on).mock.calls.find(
        call => call[0] === 'viewcontainer.sync.toggle'
      )?.[1];

      toggleHandler?.({ enabled: false });

      await waitFor(() => {
        expect(checkbox).not.toBeChecked();
      });
    });
  });

  describe('Store Subscriptions', () => {
    it('should subscribe to layer store changes', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(useLayerStore.subscribe).toHaveBeenCalled();
      });

      // Simulate layer store update
      const callback = vi.mocked(useLayerStore.subscribe).mock.calls[0][0];
      const newState = {
        layers: [],
        activeLayerId: null
      };

      vi.mocked(useLayerStore).getState.mockReturnValue(newState);
      callback(newState);

      // Should update to show loading state when no GPU layers
      await waitFor(() => {
        expect(screen.getByText('Initializing GPU context...')).toBeInTheDocument();
      });
    });

    it('should subscribe to crosshair store changes', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(useCrosshairStore.subscribe).toHaveBeenCalled();
      });
    });
  });

  describe('Cleanup', () => {
    it('should cleanup subscriptions on unmount', async () => {
      const { unmount } = render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(mockEventBus.on).toHaveBeenCalled();
      });

      unmount();

      // Check store unsubscribes were called
      expect(mockLayerStoreUnsubscribe).toHaveBeenCalled();
      expect(mockCrosshairStoreUnsubscribe).toHaveBeenCalled();

      // Check event unsubscribes were called
      mockEventUnsubscribes.forEach(unsubscribe => {
        expect(unsubscribe).toHaveBeenCalled();
      });
    });
  });

  describe('Accessibility', () => {
    it('should have accessible controls', async () => {
      render(OrthogonalViewContainer);

      await waitFor(() => {
        const checkbox = screen.getByRole('checkbox');
        expect(checkbox).toBeInTheDocument();
        expect(screen.getByText('Synchronize view scales')).toBeInTheDocument();
      });
    });

    it('should provide keyboard support for sync toggle', async () => {
      render(OrthogonalViewContainer);
      const checkbox = await screen.findByRole('checkbox');
      checkbox.focus();

      // Simulate space key press
      fireEvent.keyDown(checkbox, { key: ' ', code: 'Space' });
      fireEvent.click(checkbox);

      expect(mockEventBus.emit).toHaveBeenCalledWith('viewcontainer.sync.changed', {
        enabled: false
      });
    });
  });

  describe('Error States', () => {
    it('should display GPU error message', async () => {
      // Simulate error during initialization
      vi.mocked(getService).mockImplementation(async (serviceName) => {
        if (serviceName === 'notificationService') {
          return mockNotificationService as NotificationService;
        }
        throw new Error('Service initialization failed');
      });

      render(OrthogonalViewContainer);

      await waitFor(() => {
        expect(screen.getByText(/Failed to initialize:/)).toBeInTheDocument();
        expect(screen.getByText('GPU Initialization Error')).toBeInTheDocument();
      });
    });

    it('should not render views when GPU not initialized', () => {
      vi.mocked(useLayerStore).getState.mockReturnValue({
        layers: [{ ...mockLayers[0], gpu: false }],
        activeLayerId: 'layer1'
      });

      render(OrthogonalViewContainer);

      // Should show loading instead of views
      expect(screen.getByText('Initializing GPU context...')).toBeInTheDocument();
      expect(mockOrthogonalViewGPU).not.toHaveBeenCalled();
    });
  });
});

