beforeEach(() => {
  // Initialize test environment
  testEnvironment = null as any;
});

afterEach(() => {
  // Clean up test environment
  if (testEnvironment) {
    testEnvironment.cleanup();
  }
});

const setupComponent = (props = {}) => {
  const result = mountTestComponent(OrthogonalViewContainer, {
    props: {
      selectedLayerId: 'layer1',
      ...props
    }
  });

  testEnvironment = result.testEnvironment;
  layerService = testEnvironment.container.get<LayerService>('layerService');
  crosshairService = testEnvironment.container.get<CrosshairService>('crosshairService');
  gpuResourceService = testEnvironment.container.get<GpuResourceService>('gpuResourceService');

  // Setup initial store state
  vi.mocked(useLayerStore.getState).mockReturnValue({
    layers: mockLayers,
    selectedLayerId: 'layer1'
  });

  return result;
};

describe('Component Rendering', () => {
  it('should render with default props', async () => {
    setupComponent();

    // Should show loading initially
    expect(screen.getByText('Initializing GPU...')).toBeInTheDocument();

    // Wait for initialization
    await waitFor(() => {
      expect(screen.queryByText('Initializing GPU...')).not.toBeInTheDocument();
    });

    // Should render three views
    const views = screen.getAllByTestId('orthogonal-view-gpu');
    expect(views).toHaveLength(3);
  });

  it('should render three OrthogonalViewGPU components', async () => {
    setupComponent();

    await waitFor(() => {
      const views = screen.getAllByTestId('orthogonal-view-gpu');
      expect(views).toHaveLength(3);
    });
  });

  it('should pass selected layer ID to views', async () => {
    const { rerender } = setupComponent({ selectedLayerId: 'layer2' });

    await waitFor(() => {
      expect(screen.getAllByTestId('orthogonal-view-gpu')).toHaveLength(3);
    });

    // Update selected layer
    await rerender({ selectedLayerId: 'layer1' });
  });

  it('should show loading state initially', () => {
    setupComponent();
    expect(screen.getByText('Initializing GPU...')).toBeInTheDocument();
  });

  it('should show error state on GPU initialization failure', async () => {
    // Make GPU initialization fail
    const result = mountTestComponent(OrthogonalViewContainer, {
      props: { selectedLayerId: 'layer1' }
    });

    testEnvironment = result.testEnvironment;
    gpuResourceService = testEnvironment.container.get<GpuResourceService>('gpuResourceService');
    vi.mocked(gpuResourceService.initialize).mockRejectedValue(new Error('GPU not available'));

    // Emit GPU init error
    testEnvironment.eventBus.emit('gpu.init.error', { error: new Error('GPU not available') });

    await waitFor(() => {
      expect(screen.getByText(/Failed to initialize GPU/)).toBeInTheDocument();
    });
  });
});

describe('Service Initialization', () => {
  it('should initialize all services on mount', async () => {
    setupComponent();

    await waitFor(() => {
      expect(gpuResourceService.initialize).toHaveBeenCalled();
    });
  });

  it('should handle service initialization errors', async () => {
    const result = mountTestComponent(OrthogonalViewContainer, {
      props: { selectedLayerId: 'layer1' }
    });

    testEnvironment = result.testEnvironment;
    const notificationService = testEnvironment.container.get('notificationService');

    // Emit service error
    testEnvironment.eventBus.emit('service.error', { 
      service: 'LayerService',
      error: new Error('Service initialization failed')
    });

    await waitFor(() => {
      expect(notificationService.error).toHaveBeenCalled();
    });
  });
});

