    await waitFor(() => {
      expect(screen.queryByText('Initializing GPU...')).not.toBeInTheDocument();
    });

    // Emit context loss
    testEnvironment.eventBus.emit('gpu.context.lost', {});

    await waitFor(() => {
      expect(screen.getByText(/GPU context lost/)).toBeInTheDocument();
    });
  });

  it('should handle GPU context restoration', async () => {
    setupComponent();

    await waitFor(() => {
      expect(screen.queryByText('Initializing GPU...')).not.toBeInTheDocument();
    });

