/**
 * Helper to wait for async updates
 */
export function waitFor(ms: number = 0): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Helper to flush promises
 */
export function flushPromises(): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, 0));
}

/**
 * Helper to create a mock file
 */
export function createMockFile(
  name: string,
  type: string = 'application/octet-stream',
  size: number = 1024
): File {
  const blob = new Blob(['a'.repeat(size)], { type });
  return new File([blob], name, { type });
}

/**
 * Helper to create a mock drag event
 */
export function createMockDragEvent(
  type: string,
  files: File[] = []
): DragEvent {
  const dataTransfer = {
    files: files as any as FileList,
    items: files.map(file => ({
      kind: 'file',
      type: file.type,
      getAsFile: () => file,
    })) as any as DataTransferItemList,
    types: ['Files'],
    dropEffect: 'copy' as DataTransferEffect,
    effectAllowed: 'all' as DataTransferEffect,
    clearData: vi.fn(),
    getData: vi.fn(),
    setData: vi.fn(),
    setDragImage: vi.fn(),
  };

  return new Event(type, {
    bubbles: true,
    cancelable: true,
  }) as DragEvent & { dataTransfer: DataTransfer };
}

/**
 * Helper to mock canvas context
 */
export function createMockCanvasContext() {
  return {
    clearRect: vi.fn(),
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    fillText: vi.fn(),
    strokeText: vi.fn(),
    measureText: vi.fn().mockReturnValue({ width: 100 }),
    beginPath: vi.fn(),
    closePath: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    arc: vi.fn(),
    fill: vi.fn(),
    stroke: vi.fn(),
    save: vi.fn(),
    restore: vi.fn(),
    translate: vi.fn(),
    rotate: vi.fn(),
    scale: vi.fn(),
    setTransform: vi.fn(),
    drawImage: vi.fn(),
    createLinearGradient: vi.fn().mockReturnValue({
      addColorStop: vi.fn(),
    }),
    createRadialGradient: vi.fn().mockReturnValue({
      addColorStop: vi.fn(),
    }),
    createPattern: vi.fn(),
    getImageData: vi.fn().mockReturnValue({
      data: new Uint8ClampedArray(4),
      width: 1,
      height: 1,
    }),
    putImageData: vi.fn(),
  };
}

/**
 * Helper to create a mock HTMLCanvasElement
 */
export function createMockCanvas(
  width: number = 512,
  height: number = 512
): HTMLCanvasElement {
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;

  const ctx = createMockCanvasContext();
  canvas.getContext = vi.fn((type: string) => {
    if (type === '2d') return ctx;
    return null;
  }) as any;

  return canvas;
}

